'use client';

import React from 'react';
import {
  Scissors,
  ChevronLeft,
  ChevronRight,
  Merge,
  ArrowLeftRight,
  GripVertical,
} from 'lucide-react';

// ─── Public pure helpers ───────────────────────────────────────────

/** Format milliseconds as mm:ss.SSS */
export function formatTimecode(ms: number): string {
  const totalSeconds = Math.floor(ms / 1000);
  const minutes = Math.floor(totalSeconds / 60);
  const seconds = totalSeconds % 60;
  const millis = Math.round(ms % 1000);
  return `${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}.${String(millis).padStart(3, '0')}`;
}

/** Calculate percentage position within a clip. */
export function percentInClip(
  playheadMs: number,
  clipStartMs: number,
  clipDurationMs: number,
): number {
  if (clipDurationMs <= 0) return 0;
  const local = playheadMs - clipStartMs;
  return Math.max(0, Math.min(100, (local / clipDurationMs) * 100));
}

/** Determine if the split would produce two valid halves. */
export function canSplit(
  playheadMs: number,
  clipStartMs: number,
  clipDurationMs: number,
  minDuration: number = 100,
): boolean {
  const local = playheadMs - clipStartMs;
  return local >= minDuration && clipDurationMs - local >= minDuration;
}

/** Build a human-readable trim delta label. */
export function trimDeltaLabel(deltaMs: number): string {
  const sign = deltaMs >= 0 ? '+' : '';
  const seconds = (deltaMs / 1000).toFixed(2);
  return `${sign}${seconds}s`;
}

/** Determine toolbar action availability. */
export function getToolbarState(opts: {
  hasSelection: boolean;
  clipCount: number;
  playheadInsideClip: boolean;
  canMerge: boolean;
}): {
  splitEnabled: boolean;
  trimEnabled: boolean;
  mergeEnabled: boolean;
  reorderEnabled: boolean;
} {
  return {
    splitEnabled: opts.hasSelection && opts.playheadInsideClip,
    trimEnabled: opts.hasSelection,
    mergeEnabled: opts.hasSelection && opts.canMerge && opts.clipCount >= 2,
    reorderEnabled: opts.clipCount >= 2,
  };
}

// ─── Props ─────────────────────────────────────────────────────────

export interface TrimSplitToolbarProps {
  /** Current playhead position in ms */
  playheadMs: number;
  /** Selected clip start time in ms */
  clipStartMs?: number;
  /** Selected clip duration in ms */
  clipDurationMs?: number;
  /** Selected clip name */
  clipName?: string;
  /** Whether a clip is currently selected */
  hasSelection: boolean;
  /** Number of clips on the timeline */
  clipCount: number;
  /** Whether adjacent clips can be merged */
  canMergeAdjacent: boolean;

  /** Callbacks */
  onSplit?: () => void;
  onTrimIn?: () => void;
  onTrimOut?: () => void;
  onMerge?: () => void;
  onReorder?: () => void;
}

// ─── Component ─────────────────────────────────────────────────────

/**
 * Toolbar for trim, split, merge, and reorder operations on timeline clips.
 *
 * This component is purely presentational — it receives state and emits
 * callbacks. All logic lives in the trim-split-engine.
 */
export default function TrimSplitToolbar({
  playheadMs,
  clipStartMs = 0,
  clipDurationMs = 0,
  clipName,
  hasSelection,
  clipCount,
  canMergeAdjacent,
  onSplit,
  onTrimIn,
  onTrimOut,
  onMerge,
  onReorder,
}: TrimSplitToolbarProps) {
  const playheadInsideClip =
    hasSelection && playheadMs > clipStartMs && playheadMs < clipStartMs + clipDurationMs;

  const state = getToolbarState({
    hasSelection,
    clipCount,
    playheadInsideClip,
    canMerge: canMergeAdjacent,
  });

  const splitPercent = hasSelection ? percentInClip(playheadMs, clipStartMs, clipDurationMs) : 0;

  return (
    <div className="flex items-center gap-1 rounded-lg border border-zinc-700 bg-zinc-900 px-2 py-1">
      {/* Clip info */}
      <div className="mr-2 min-w-[120px] text-xs text-zinc-400">
        {hasSelection ? (
          <>
            <span className="font-medium text-zinc-200">{clipName ?? 'Clip'}</span>
            <span className="ml-1 tabular-nums">
              {formatTimecode(clipStartMs)} — {formatTimecode(clipStartMs + clipDurationMs)}
            </span>
          </>
        ) : (
          <span className="italic">Nenhum clip selecionado</span>
        )}
      </div>

      {/* Divider */}
      <div className="mx-1 h-5 w-px bg-zinc-700" />

      {/* Trim In */}
      <button
        type="button"
        title="Trim início (I)"
        disabled={!state.trimEnabled}
        onClick={onTrimIn}
        className="inline-flex items-center justify-center rounded p-1.5 text-zinc-400 hover:bg-zinc-800 hover:text-white disabled:cursor-not-allowed disabled:opacity-40"
      >
        <ChevronRight className="h-4 w-4" />
      </button>

      {/* Split */}
      <button
        type="button"
        title="Split no playhead (S)"
        disabled={!state.splitEnabled}
        onClick={onSplit}
        className="inline-flex items-center justify-center rounded p-1.5 text-zinc-400 hover:bg-zinc-800 hover:text-white disabled:cursor-not-allowed disabled:opacity-40"
      >
        <Scissors className="h-4 w-4" />
      </button>

      {/* Trim Out */}
      <button
        type="button"
        title="Trim fim (O)"
        disabled={!state.trimEnabled}
        onClick={onTrimOut}
        className="inline-flex items-center justify-center rounded p-1.5 text-zinc-400 hover:bg-zinc-800 hover:text-white disabled:cursor-not-allowed disabled:opacity-40"
      >
        <ChevronLeft className="h-4 w-4" />
      </button>

      {/* Divider */}
      <div className="mx-1 h-5 w-px bg-zinc-700" />

      {/* Merge */}
      <button
        type="button"
        title="Mesclar clips adjacentes (M)"
        disabled={!state.mergeEnabled}
        onClick={onMerge}
        className="inline-flex items-center justify-center rounded p-1.5 text-zinc-400 hover:bg-zinc-800 hover:text-white disabled:cursor-not-allowed disabled:opacity-40"
      >
        <Merge className="h-4 w-4" />
      </button>

      {/* Reorder */}
      <button
        type="button"
        title="Reordenar clips (R)"
        disabled={!state.reorderEnabled}
        onClick={onReorder}
        className="inline-flex items-center justify-center rounded p-1.5 text-zinc-400 hover:bg-zinc-800 hover:text-white disabled:cursor-not-allowed disabled:opacity-40"
      >
        <GripVertical className="h-4 w-4" />
      </button>

      {/* Divider */}
      <div className="mx-1 h-5 w-px bg-zinc-700" />

      {/* Split position indicator */}
      {state.splitEnabled && (
        <div className="flex items-center gap-1 text-xs text-amber-400">
          <ArrowLeftRight className="h-3 w-3" />
          <span className="tabular-nums">{splitPercent.toFixed(0)}%</span>
        </div>
      )}

      {/* Playhead timecode */}
      <div className="ml-auto text-xs tabular-nums text-zinc-500">{formatTimecode(playheadMs)}</div>
    </div>
  );
}
